import { initializeApp, getApps } from 'firebase-admin/app';
import { getMessaging } from 'firebase-admin/messaging';

// Lazy init
let messaging: ReturnType<typeof getMessaging> | null = null;
const getMessagingClient = () => {
  if (!messaging) {
    if (!getApps().length) {
      initializeApp({ credential: JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT || '{}') });
    }
    messaging = getMessaging();
  }
  return messaging;
};

export class FcmPushService {
  async sendToToken(token: string, notification: { title: string; body: string }, data?: Record<string, string>): Promise<string> {
    const msgId = await getMessagingClient().send({
      token,
      notification,
      data,
      android: { priority: 'high' },
      apns: { payload: { aps: { contentAvailable: true } } },
    });
    return msgId;
  }

  async sendToTopic(topic: string, notification: { title: string; body: string }, data?: Record<string, string>): Promise<string> {
