/**
 * NotifyService — adapter layer for 4-collection model.
 * Maps to existing API response shapes expected by FE.
 * Replaces NotificationService + AnnouncementService.
 */
import { NotifyRepository, AdaptedNotification } from '@/infrastructure/database/repositories/notify.repository';
import { PaginationOptions, PaginatedResult } from '@/domain/types/pagination.types';
import NotifyContent from '@/infrastructure/database/models/notify_content.model';
import Notify from '@/infrastructure/database/models/notify.model';
import { Types } from 'mongoose';

export class NotifyService {
  private repo: NotifyRepository;

  constructor() {
    this.repo = new NotifyRepository();
  }

  // ── Notifications (per-user) ───────────────────────────────────────────────

  async getByUser(
    userId: string,
    options?: PaginationOptions,
  ): Promise<PaginatedResult<AdaptedNotification>> {
    return this.repo.findByUserId(userId, options);
  }

  async send(data: {
    userId: string;
    title: string;
    content: string;
    channel?: string;
    data?: Record<string, unknown>;
  }): Promise<AdaptedNotification> {
    return this.repo.sendNotification(data);
  }

  async markAsRead(notifyUserId: string, userId: string) {
    return this.repo.markAsRead(notifyUserId, userId);
  }

  async markAllAsRead(userId: string) {
    return this.repo.markAllAsRead(userId);
  }

  async getUnreadCount(userId: string): Promise<number> {
    return this.repo.countUnreadByUserId(userId);
  }

  async deleteNotification(notifyUserId: string, userId?: string) {
    // Find the NotifyUser to get the notify_id, then delete from notifyUsers
    return this.repo.deleteNotifyUser(notifyUserId, userId);
  }

  // ── Announcements (admin broadcast) ────────────────────────────────────────

  async getAnnouncements(options: PaginationOptions & { search?: string; status?: string }) {
    const { page, limit, search, status } = options;
    const skip = (page - 1) * limit;

    const query: Record<string, unknown> = { types: 'announcement' };
    if (search) {
      query.$or = [
        { title: { $regex: search, $options: 'i' } },
        { content: { $regex: search, $options: 'i' } },
      ];
    }
    if (status) {
      // Map FE status to notifies.status
      const notifyStatusMap: Record<string, string> = {
        SENT: 'sent',
        SCHEDULED: 'draft',
      };
      // For now, filter by content status via data lookup
      // (simplified: just return all announcements sorted by created_at desc)
    }

    const [docs, total] = await Promise.all([
      NotifyContent.find(query).sort({ created_at: -1 }).skip(skip).limit(limit).lean().exec(),
      NotifyContent.countDocuments(query).exec(),
    ]);

    const data = await Promise.all(
      docs.map(async (doc) => {
        const notify = await Notify.findOne({ content_id: doc._id }).lean().exec();
        const extra = (doc.data || {}) as Record<string, unknown>;
        return {
          id: doc._id.toString(),
          title: doc.title,
          content: doc.content,
          sub_title: doc.sub_title,
          sub_content: doc.sub_content,
          target_group: (extra.target_group as string) || 'ALL',
          channels: (extra.channels as string[]) || [],
          status: notify?.status === 'sent' ? 'SENT' : 'SCHEDULED',
          scheduled_at: extra.scheduled_at,
          created_by: extra.created_by,
          createdAt: doc.created_at,
          updatedAt: doc.updated_at,
        };
      }),
    );

    return {
      data,
      meta: {
        total,
        page,
        limit,
        total_pages: Math.ceil(total / limit),
      },
    };
  }

  async createAnnouncement(data: {
    title: string;
    content: string;
    target_group: string;
    channels: string[];
    status?: string;
    scheduled_at?: Date;
    created_by?: string;
  }) {
    const result = await this.repo.broadcastAnnouncement({
      title: data.title,
      content: data.content,
      types: 'announcement',
      target_group: data.target_group,
      channels: data.channels,
      scheduled_at: data.scheduled_at,
      created_by: data.created_by ? new Types.ObjectId(data.created_by) : undefined,
      status: data.status === 'SENT' ? 'sent' : 'draft',
    });

    return {
      id: ((result.notify as unknown) as { _id: Types.ObjectId })._id.toString(),
      title: data.title,
      content: data.content,
      target_group: data.target_group,
      channels: data.channels,
      status: data.status || 'SENT',
      scheduled_at: data.scheduled_at,
      created_by: data.created_by,
      createdAt: ((result.notify as unknown) as { created_at: Date }).created_at,
      updatedAt: ((result.notify as unknown) as { updated_at: Date }).updated_at,
    };
  }

  async updateAnnouncement(id: string, data: Partial<{
    title: string;
    content: string;
    target_group: string;
    channels: string[];
    status: string;
    scheduled_at: Date;
  }>) {
    const content = await NotifyContent.findByIdAndUpdate(
      id,
      {
        $set: {
          ...(data.title ? { title: data.title } : {}),
          ...(data.content ? { content: data.content } : {}),
          'data.target_group': data.target_group,
          'data.channels': data.channels,
        },
      },
      { new: true },
    ).lean().exec();

    if (!content) return null;

    const notify = await Notify.findOneAndUpdate(
      { content_id: new Types.ObjectId(id) },
      {
        $set: {
          status: data.status === 'SENT' ? 'sent' : 'draft',
        },
      },
      { new: true },
    ).lean().exec();

    return content ? {
      id: content._id.toString(),
      ...content,
      status: notify?.status,
    } : null;
  }

  async deleteAnnouncement(id: string) {
    const notify = await Notify.findOneAndDelete({ content_id: new Types.ObjectId(id) }).lean().exec();
    if (notify) {
      await this.repo.deleteNotifyUser(notify._id.toString());
    }
    const result = await NotifyContent.findByIdAndDelete(id).lean().exec();
    return !!result;
  }
}

import { Types } from 'mongoose';
import { PaginationOptions, PaginatedResult } from '@/domain/types/pagination.types';
import NotifyContent from '@/infrastructure/database/models/notify_content.model';
import Notify from '@/infrastructure/database/models/notify.model';
import NotifyUser from '@/infrastructure/database/models/notify_user.model';
import NotifyConfig from '@/infrastructure/database/models/notify_config.model';
import { UserModel } from '@/infrastructure/database/models/user.model';

// ─── Adapted response shape (matches existing FE API contract) ─────────────────

export interface AdaptedNotification {
  id: string;
  userId: string;
  channel: string;
  title: string;
  content: string;
  targetGroup: string;
  status: 'unread' | 'read';
  createdAt: Date;
  data?: Record<string, unknown>;
}

// ─── Repository ────────────────────────────────────────────────────────────────

export class NotifyRepository {
  // ── NotifyContent helpers ──────────────────────────────────────────────────

  async createContent(data: {
    title: string;
    content: string;
    sub_title?: string;
    sub_content?: string;
    types: string;
    data?: Record<string, unknown>;
  }) {
    const doc = await NotifyContent.create(data);
    return doc.toObject({ getters: true, virtuals: true, versionKey: false }) as typeof doc extends unknown[] ? never : Awaited<ReturnType<typeof doc.toObject>>;
  }

  async findContentById(id: string) {
    return NotifyContent.findById(id).lean().exec();
  }

  // ── Notify helpers ────────────────────────────────────────────────────────

  async createNotify(data: {
    content_id: Types.ObjectId;
    config_id: Types.ObjectId;
    status: string;
  }) {
    const doc = await Notify.create(data);
    return doc.toObject({ getters: true, virtuals: true, versionKey: false });
  }

  async findNotifyById(id: string) {
    return Notify.findById(id).lean().exec();
  }

  async findNotifyByContentId(contentId: string) {
    return Notify.findOne({ content_id: new Types.ObjectId(contentId) }).lean().exec();
  }

  async deleteNotifyById(id: string) {
    // Cascade delete: NotifyUser rows first
    await NotifyUser.deleteMany({ notify_id: new Types.ObjectId(id) }).exec();
    return Notify.findByIdAndDelete(id).lean().exec();
  }

  // ── NotifyUser helpers ─────────────────────────────────────────────────────

  async createNotifyUser(data: {
    notify_id: Types.ObjectId;
    user_id: Types.ObjectId;
    status: string;
    data?: Record<string, unknown>;
  }) {
    const doc = await NotifyUser.create(data);
    return doc.toObject({ getters: true, virtuals: true, versionKey: false });
  }

  async markAsRead(notifyId: string, userId: string) {
    const updated = await NotifyUser.findOneAndUpdate(
      {
        notify_id: new Types.ObjectId(notifyId),
        user_id: new Types.ObjectId(userId),
      },
      {
        $set: {
          status: 'read',
          ...(!(await this._hasReadAtField())
            ? {}
            : { 'data.read_at': new Date() }),
        },
      },
      { new: true },
    )
      .populate('notify_id')
      .lean()
      .exec();
    return updated;
  }

  private async _hasReadAtField(): Promise<boolean> {
    return false; // we use the top-level status, data.read_at is optional
  }

  async markAllAsRead(userId: string) {
    await NotifyUser.updateMany(
      {
        user_id: new Types.ObjectId(userId),
        status: 'unread',
      },
      { $set: { status: 'read' } },
    ).exec();
  }

  async countUnreadByUserId(userId: string): Promise<number> {
    return NotifyUser.countDocuments({
      user_id: new Types.ObjectId(userId),
      status: 'unread',
    }).exec();
  }

  async deleteNotifyUser(notifyId: string, userId?: string) {
    const query: Record<string, unknown> = { notify_id: new Types.ObjectId(notifyId) };
    if (userId) query.user_id = new Types.ObjectId(userId);
    await NotifyUser.deleteMany(query).exec();
  }

  // ── Broadcast: create NotifyContent + Notify + all NotifyUser rows ──────────

  async broadcastAnnouncement(data: {
    title: string;
    content: string;
    types: string;
    target_group: string;
    channels?: string[];
    scheduled_at?: Date;
    created_by?: Types.ObjectId;
    channel?: string;
    status?: string;
  }) {
    // 1. Create NotifyContent
    const content = await this.createContent({
      title: data.title,
      content: data.content,
      types: data.types,
      data: {
        target_group: data.target_group,
        channels: data.channels,
        scheduled_at: data.scheduled_at,
        created_by: data.created_by,
        channel: data.channel,
      },
    });
    const contentId = (content as any).id;

    // 2. Get default config
    const config = await NotifyConfig.findOne({ active: true }).lean().exec();
    if (!config) throw new Error('No active NotifyConfig found');

    // 3. Create Notify
    const notify = await this.createNotify({
      content_id: contentId,
      config_id: config._id as Types.ObjectId,
      status: data.status || 'sent',
    });
    const notifyId = (notify as any).id;

    // 4. Create NotifyUser for each target user
    const roleMap: Record<string, Record<string, unknown>> = {
      ALL: {},
      STUDENT: { role: 'student' },
      TEACHER: { role: 'teacher' },
      STAFF: { role: { $in: ['admin', 'staff'] } },
    };
    const userFilter = roleMap[data.target_group] || {};
    const users = await UserModel.find(userFilter, { _id: 1, role: 1 }).lean().exec();

    if (users.length > 0) {
      const now = new Date();
      const docs = users.map((u) => ({
        notify_id: notifyId,
        user_id: u._id,
        status: 'unread',
        data: {
          receive_type:
            u.role === 'student' ? 'student' : u.role === 'teacher' ? 'teacher' : 'user',
          delivered_at: now,
        },
      }));
      await NotifyUser.insertMany(docs, { ordered: false }).catch(() => {
        /* skip duplicate key errors */
      });
    }

    return { content, notify, recipientCount: users.length };
  }

  // ── Get paginated notifications for a user (JOIN across 4 collections) ──────

  async findByUserId(
    userId: string,
    options: PaginationOptions = { page: 1, limit: 10 },
  ): Promise<PaginatedResult<AdaptedNotification>> {
    const { page, limit } = options;
    const skip = (page - 1) * limit;

    const userOid = new Types.ObjectId(userId);

    const [rows, total] = await Promise.all([
      NotifyUser.find({ user_id: userOid })
        .sort({ created_at: -1 })
        .skip(skip)
        .limit(limit)
        .lean()
        .exec(),
      NotifyUser.countDocuments({ user_id: userOid }).exec(),
    ]);

    if (rows.length === 0) {
      return {
        data: [],
        meta: { total: 0, page, limit, total_pages: 0 },
      };
    }

    // Collect all notify_ids and do a single $lookup via populate
    const notifyIds = rows.map((r) => r.notify_id);
    const notifies = await Notify.find({ _id: { $in: notifyIds } })
      .populate<{ content_id: unknown }>('content_id')
      .lean()
      .exec();

    const notifyMap = new Map(notifies.map((n) => [n._id.toString(), n]));

    const adapted: AdaptedNotification[] = [];
    for (const ru of rows) {
      const notify = notifyMap.get(ru.notify_id.toString());
      if (!notify) continue;

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const content = notify.content_id as any;
      if (!content || !content._id) continue;

      const extra = (content.data || {}) as Record<string, unknown>;
      adapted.push({
        id: ru._id.toString(),
        userId: ru.user_id.toString(),
        channel: (extra.channel as string) || 'in_app',
        title: content.title || '',
        content: content.content || '',
        targetGroup: (extra.target_group as string) || 'ALL',
        status: ru.status as 'unread' | 'read',
        createdAt: ru.created_at,
        data: content.data as Record<string, unknown>,
      });
    }
    return { data: adapted, meta: { total, page, limit, total_pages: Math.ceil(total / limit) } };
  }

  // ── Send single notification ────────────────────────────────────────────────

  async sendNotification(data: {
    userId: string;
    title: string;
    content: string;
    channel?: string;
    data?: Record<string, unknown>;
  }) {
    const config = await NotifyConfig.findOne({ active: true }).lean().exec();
    if (!config) throw new Error('No active NotifyConfig found');

    const content = await this.createContent({
      title: data.title,
      content: data.content,
      types: 'system',
      data: data.data,
    });
    const contentId = (content as any).id;

    const notify = await this.createNotify({
      content_id: contentId,
      config_id: config._id as Types.ObjectId,
      status: 'sent',
    });
    const notifyId = (notify as any).id;

    const user = await this.createNotifyUser({
      notify_id: notifyId,
      user_id: new Types.ObjectId(data.userId),
      status: 'unread',
      data: { receive_type: 'user' },
    });

    return {
      id: (user as unknown as { _id: Types.ObjectId })._id.toString(),
      userId: data.userId,
      channel: data.channel || 'in_app',
      title: data.title,
      content: data.content,
      targetGroup: '',
      status: 'unread' as const,
      createdAt: (user as unknown as { created_at: Date }).created_at,
    };
  }
}

