import twilio from 'twilio';

const client = twilio(
  process.env.TWILIO_ACCOUNT_SID,
  process.env.TWILIO_AUTH_TOKEN
);

export class TwilioSmsService {
  async send(phone: string, message: string): Promise<{ sid: string; status: string }> {
    return client.messages.create({
      body: message,
      from: process.env.TWILIO_PHONE_NUMBER,
      to: phone,
    });
  }
}

// Zalo OA API v3 — send text message
export class ZaloOaService {
  private appId = process.env.ZALO_APP_ID!;
  private appSecret = process.env.ZALO_APP_SECRET!;
  private oaId = process.env.ZALO_OA_ID!;
  private accessToken: string | null = null;
  private tokenExpiry = 0;

  private async getAccessToken(): Promise<string> {
    if (this.accessToken && Date.now() < this.tokenExpiry) {
      return this.accessToken;
    }
    const res = await fetch(
      `https://graph.zalo.me/v2.0/oa/access_token?app_id=${this.appId}&app_secret=${this.appSecret}&grant_type=client_credentials`,
      { method: 'POST' }
    );
    const data = await res.json();
    this.accessToken = data.access_token;
    this.tokenExpiry = Date.now() + (data.expires_in - 60) * 1000;
    return this.accessToken;
  }

  async sendText(userId: string, message: string): Promise<{ success: boolean }> {
    const token = await this.getAccessToken();
    const res = await fetch(`https://graph.zalo.me/v2.0/zsns/user_message`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`,
        access_token: this.accessToken,
      },
      body: JSON.stringify({
        recipient: { user_id: userId },
        message: { text: message },
        oa_id: this.oaId,
      }),
    });
    return res.json();
  }
}

import { initializeApp, getApps } from 'firebase-admin/app';
import { getMessaging } from 'firebase-admin/messaging';

// Lazy init
let messaging: ReturnType<typeof getMessaging> | null = null;
const getMessagingClient = () => {
  if (!messaging) {
    if (!getApps().length) {
      initializeApp({ credential: JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT || '{}') });
    }
    messaging = getMessaging();
  }
  return messaging;
};

export class FcmPushService {
  async sendToToken(token: string, notification: { title: string; body: string }, data?: Record<string, string>): Promise<string> {
    const msgId = await getMessagingClient().send({
      token,
      notification,
      data,
      android: { priority: 'high' },
      apns: { payload: { aps: { contentAvailable: true } } },
    });
    return msgId;
  }

  async sendToTopic(topic: string, notification: { title: string; body: string }, data?: Record<string, string>): Promise<string> {
    const msgId = await getMessagingClient().send({
      topic,
      notification,
      data,
    });
    return msgId;
  }
}

import { TwilioSmsService } from './twilio-sms.service';
import { ZaloOaService } from './zalo-oa.service';
import { FcmPushService } from './fcm-push.service';

export type NotifyChannel = 'sms' | 'zalo' | 'fcm' | 'in_app';

export class NotificationDispatcher {
  private sms = new TwilioSmsService();
  private zalo = new ZaloOaService();
  private fcm = new FcmPushService();

  async dispatch(channel: NotifyChannel, payload: {
    recipient: string; // phone for sms, zalo_user_id for zalo, fcm_token for fcm
    title: string;
    body: string;
    data?: Record<string, unknown>;
  }): Promise<{ success: boolean; channel: NotifyChannel; messageId?: string; error?: string }> {
    try {
      switch (channel) {
        case 'sms': {
          const result = await this.sms.send(payload.recipient, `${payload.title}\n${payload.body}`);
          return { success: true, channel, messageId: result.sid };
        }
        case 'zalo': {
          const result = await this.zalo.sendText(payload.recipient, `${payload.title}\n${payload.body}`);
          return { success: result.success, channel, messageId: result.success ? 'ok' : undefined };
        }
        case 'fcm': {
          const msgId = await this.fcm.sendToToken(
            payload.recipient,
            { title: payload.title, body: payload.body },
            payload.data as Record<string, string>
          );
          return { success: true, channel, messageId: msgId };
        }
        case 'in_app':
        default:
          return { success: true, channel, messageId: undefined }; // stored in DB by NotifyService
      }
    } catch (err) {
      const error = err instanceof Error ? err.message : String(err);
      return { success: false, channel, error };
    }
  }
}

