/**
 * NotifyService — adapter layer for 4-collection model.
 * Maps to existing API response shapes expected by FE.
 * Replaces NotificationService + AnnouncementService.
 */
import { NotifyRepository, AdaptedNotification } from '@/infrastructure/database/repositories/notify.repository';
import { PaginationOptions, PaginatedResult } from '@/domain/types/pagination.types';
import NotifyContent from '@/infrastructure/database/models/notify_content.model';
import Notify from '@/infrastructure/database/models/notify.model';
import { Types } from 'mongoose';

export class NotifyService {
  private repo: NotifyRepository;

  constructor() {
    this.repo = new NotifyRepository();
  }

  // ── Notifications (per-user) ───────────────────────────────────────────────

  async getByUser(
    userId: string,
    options?: PaginationOptions,
  ): Promise<PaginatedResult<AdaptedNotification>> {
    return this.repo.findByUserId(userId, options);
  }

  async send(data: {
    userId: string;
    title: string;
    content: string;
    channel?: string;
    data?: Record<string, unknown>;
  }): Promise<AdaptedNotification> {
    return this.repo.sendNotification(data);
  }

  async markAsRead(notifyUserId: string, userId: string) {
    return this.repo.markAsRead(notifyUserId, userId);
  }

  async markAllAsRead(userId: string) {
    return this.repo.markAllAsRead(userId);
  }

  async getUnreadCount(userId: string): Promise<number> {
    return this.repo.countUnreadByUserId(userId);
  }

  async deleteNotification(notifyUserId: string, userId?: string) {
    // Find the NotifyUser to get the notify_id, then delete from notifyUsers
    return this.repo.deleteNotifyUser(notifyUserId, userId);
  }

  // ── Announcements (admin broadcast) ────────────────────────────────────────

  async getAnnouncements(options: PaginationOptions & { search?: string; status?: string }) {
    const { page, limit, search, status } = options;
    const skip = (page - 1) * limit;

    const query: Record<string, unknown> = { types: 'announcement' };
    if (search) {
      query.$or = [
        { title: { $regex: search, $options: 'i' } },
        { content: { $regex: search, $options: 'i' } },
      ];
    }
    if (status) {
      // Map FE status to notifies.status
      const notifyStatusMap: Record<string, string> = {
        SENT: 'sent',
        SCHEDULED: 'draft',
      };
      // For now, filter by content status via data lookup
      // (simplified: just return all announcements sorted by created_at desc)
    }

    const [docs, total] = await Promise.all([
      NotifyContent.find(query).sort({ created_at: -1 }).skip(skip).limit(limit).lean().exec(),
      NotifyContent.countDocuments(query).exec(),
    ]);

    const data = await Promise.all(
      docs.map(async (doc) => {
        const notify = await Notify.findOne({ content_id: doc._id }).lean().exec();
        const extra = (doc.data || {}) as Record<string, unknown>;
        return {
          id: doc._id.toString(),
          title: doc.title,
          content: doc.content,
          sub_title: doc.sub_title,
          sub_content: doc.sub_content,
          target_group: (extra.target_group as string) || 'ALL',
          channels: (extra.channels as string[]) || [],
          status: notify?.status === 'sent' ? 'SENT' : 'SCHEDULED',
          scheduled_at: extra.scheduled_at,
          created_by: extra.created_by,
          createdAt: doc.created_at,
          updatedAt: doc.updated_at,
        };
      }),
    );

    return {
      data,
      meta: {
        total,
        page,
        limit,
        total_pages: Math.ceil(total / limit),
      },
    };
  }

  async createAnnouncement(data: {
    title: string;
    content: string;
    target_group: string;
    channels: string[];
    status?: string;
    scheduled_at?: Date;
    created_by?: string;
  }) {
    const result = await this.repo.broadcastAnnouncement({
      title: data.title,
      content: data.content,
      types: 'announcement',
      target_group: data.target_group,
      channels: data.channels,
      scheduled_at: data.scheduled_at,
      created_by: data.created_by ? new Types.ObjectId(data.created_by) : undefined,
      status: data.status === 'SENT' ? 'sent' : 'draft',
    });

    return {
      id: ((result.notify as unknown) as { _id: Types.ObjectId })._id.toString(),
      title: data.title,
      content: data.content,
      target_group: data.target_group,
      channels: data.channels,
      status: data.status || 'SENT',
      scheduled_at: data.scheduled_at,
      created_by: data.created_by,
      createdAt: ((result.notify as unknown) as { created_at: Date }).created_at,
      updatedAt: ((result.notify as unknown) as { updated_at: Date }).updated_at,
    };
  }

  async updateAnnouncement(id: string, data: Partial<{
    title: string;
    content: string;
    target_group: string;
    channels: string[];
    status: string;
    scheduled_at: Date;
  }>) {
    const content = await NotifyContent.findByIdAndUpdate(
      id,
      {
        $set: {
          ...(data.title ? { title: data.title } : {}),
          ...(data.content ? { content: data.content } : {}),
          'data.target_group': data.target_group,
          'data.channels': data.channels,
        },
      },
      { new: true },
    ).lean().exec();

    if (!content) return null;

    const notify = await Notify.findOneAndUpdate(
      { content_id: new Types.ObjectId(id) },
      {
        $set: {
          status: data.status === 'SENT' ? 'sent' : 'draft',
        },
      },
      { new: true },
    ).lean().exec();

    return content ? {
      id: content._id.toString(),
      ...content,
      status: notify?.status,
    } : null;
  }

  async deleteAnnouncement(id: string) {
    const notify = await Notify.findOneAndDelete({ content_id: new Types.ObjectId(id) }).lean().exec();
    if (notify) {
      await this.repo.deleteNotifyUser(notify._id.toString());
    }
    const result = await NotifyContent.findByIdAndDelete(id).lean().exec();
    return !!result;
  }
}

