async send(data: {
  userId: string;
  title: string;
  content: string;
  channel?: string;
  channels?: string[];
  data?: Record<string, unknown>;
}): Promise<AdaptedNotification> {
  const result = await this.repo.sendNotification(data);

  // Dispatch to external channels after DB save
  const channelsToDispatch: string[] = data.channels || (data.channel ? [data.channel] : ['in_app']);

  // Map FE channel names → NotifyChannel + fetch user recipient
  const user = await UserModel.findById(data.userId).lean().exec();
  if (user) {
    const dispatcher = new NotificationDispatcher();
    const channelMap: Record<string, NotifyChannel> = {
      Zalo: 'zalo',
      Telegram: 'in_app',
      CMS: 'in_app',
      Mobile: 'in_app',
      sms: 'sms',
      zalo: 'zalo',
      fcm: 'fcm',
      in_app: 'in_app',
    };

    for (const ch of channelsToDispatch) {
      const notifyChannel = channelMap[ch] ?? 'in_app';
      let recipient = '';

      if (notifyChannel === 'sms') {
        recipient = (user as { phone?: string }).phone || '';
      } else if (notifyChannel === 'zalo') {
        recipient = (user as { zalo_user_id?: string }).zalo_user_id || '';
      } else if (notifyChannel === 'fcm') {
        recipient = (user as { fcm_token?: string }).fcm_token || '';
      } else {
        recipient = 'in_app';
      }

      if (recipient) {
        await dispatcher.dispatch(notifyChannel, {
          recipient,
          title: data.title,
          body: data.content,
          data: data.data,
        });
      }
    }
  }

  return result;
}

